import logging
import os
from typing import Optional
from azure.storage.blob import BlobServiceClient
from azure.core.exceptions import ResourceNotFoundError, AzureError
from azure.functions import HttpRequest, HttpResponse

def main(req: HttpRequest) -> HttpResponse:
    try:
        # Get blob path from query parameters
        blob_path = req.params.get('path')
        
        if not blob_path:
            return HttpResponse(
                "Blob path is required",
                status_code=400,
                mimetype="text/plain"
            )
        
        # Validate blob path to prevent directory traversal
        if '..' in blob_path or blob_path.startswith('/'):
            return HttpResponse(
                "Invalid blob path",
                status_code=400,
                mimetype="text/plain"
            )
        
        # Get connection string from environment variable
        connection_string = os.environ.get('AzureWebJobsStorage')
        if not connection_string:
            return HttpResponse(
                "Storage connection string not configured",
                status_code=500,
                mimetype="text/plain"
            )
        
        # Create blob service client
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        
        # Extract container name and blob name
        parts = blob_path.strip('/').split('/', 1)
        if len(parts) < 2:
            return HttpResponse(
                "Invalid blob path format",
                status_code=400,
                mimetype="text/plain"
            )
        
        container_name = parts[0]
        blob_name = parts[1]
        
        # Get blob client
        blob_client = blob_service_client.get_blob_client(
            container=container_name,
            blob=blob_name
        )
        
        # Read blob content
        blob_data = blob_client.download_blob().readall()
        
        # Get content type from blob metadata or default to binary
        content_type = blob_client.get_blob_properties().content_settings.content_type if hasattr(blob_client.get_blob_properties(), 'content_settings') else 'application/octet-stream'
        
        return HttpResponse(
            body=blob_data,
            status_code=200,
            mimetype=content_type
        )
        
    except ResourceNotFoundError:
        return HttpResponse(
            "File not found",
            status_code=404,
            mimetype="text/plain"
        )
    except AzureError as e:
        logging.error(f"Azure error: {str(e)}")
        return HttpResponse(
            "Internal server error",
            status_code=500,
            mimetype="text/plain"
        )
    except Exception as e:
        logging.error(f"Unexpected error: {str(e)}")
        return HttpResponse(
            "Internal server error",
            status_code=500,
            mimetype="text/plain"
        )